use std::fs::File;
use std::io::{self, Write};

struct SensorRecord {
    timestamp: u64,
    voltage_a: f32,
    current_b: i32,
}

fn main() -> io::Result<()> {
    let records: Vec<SensorRecord> = vec![
        SensorRecord { timestamp: 1678886400, voltage_a: 3.31, current_b: 1024 },
        SensorRecord { timestamp: 1678886405, voltage_a: 3.30, current_b: 1019 } 
    ];

    let file = File::create("sensor_data.parquet")?;
    let mut writer = std::io::BufWriter::new(file);

    for record in records {
        let mut buffer = Vec::with_capacity(32);
        buffer.extend_from_slice(&record.timestamp.to_le_bytes());
        buffer.extend_from_slice(&record.voltage_a.to_bits().to_le_bytes());
        buffer.extend_from_slice(&record.current_b.to_le_bytes());
        writer.write_all(&buffer)?; 
    }

    writer.flush()?;
    Ok(())
}

use std::error::Error;
use std::fs::File;
use std::io::{self, Write, Read};

struct ConfigManager {
    paths: Vec<String>,
}

impl ConfigManager {
    fn new(initial_paths: Vec<String>) -> Self {
        ConfigManager { paths: initial_paths }
    }

    fn save_config(&self, file_path: &str) -> Result<(), Box<dyn Error>> {
        let mut file = File::create(file_path)?;
        for path in &self.paths {
            writeln!(file, "{}", path)?;
        }
        Ok(())
    }

    fn load_config(file_path: &str) -> Result<Vec<String>, Box<dyn Error>> {
        let mut file = File::open(file_path)?;
        let mut contents = String::new();
        file.read_to_string(&mut contents)?;
        Ok(contents.trim().split('n').filter(|s| !s.is_empty()).map(|s| s.to_string()).collect())
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let initial = vec!["~/config/nvim".to_string(), "~/dotfile/git".to_string()];
    let manager = ConfigManager::new(initial);
    let save_file = "settings.txt";

    manager.save_config(save_file)?;

    let loaded_paths = ConfigManager::load_config(save_file)?;
    println!("Successfully loaded {} paths.", loaded_paths.len());

    Ok(())
}

