use std::collections::HashMap;
use std::fs::File;
use std::io::{BufReader, BufRead};

struct Record {
    id: u64,
    name: String,
    value: String,
}

fn process_records(reader: BufReader<File>, key_filter: &str) -> Vec<String> {
    let mut results = Vec::new();
    let mut records: HashMap<u64, Record> = HashMap::new();

    for line in reader.lines() {
        let line = line.unwrap();
        if line.is_empty() { continue; }

        let parts: Vec<&str> = line.split(",").collect();
        if parts.len() < 3 {
            continue;
        }

        let id = match parts[0].parse::<u64>() {
            Ok(val) => val,
            Err(_) => continue,
        };
        let name = parts[1].to_string();
        let value = parts[2].to_string();

        records.insert(id, Record { id, name, value });
    }

    for (_, record) in records.iter() {
        if record.name.contains(key_filter) {
            results.push(format!("Found ID {} for name {}", record.id, record.value));
        }
    }
    results
}

use std::error::Error;
use std::fs::File;
use std::io::{self, Write};

struct SimulationState {
    id: u32,
    timestamp: String,
    energy_level: f64,
}

fn write_to_parquet_like(file_path: &str, states: &[SimulationState]) -> Result<(), Box<dyn Error>> {
    let mut file = File::create(file_path)?;
    writeln!(file, "id,timestamp,energy_level")?;

    for state in states {
        writeln!(file, "{},\"{}\",{}", state.id, state.timestamp, state.energy_level)?;
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let states = vec![
        SimulationState { id: 101, timestamp: "2024-05-28T10:00:00Z".to_string(), energy_level: 3.14159 },
        SimulationState { id: 102, timestamp: "2024-05-28T10:01:00Z".to_string(), energy_level: 2.71828 },
    ];
    write_to_parquet_like("simulation_output.csv", &states)?; 
    println!("Successfully wrote simulation state to disk.");
    Ok(())
}
